mapper.select:
    select 

    from T_COMP_RTCHECKRES 



                and L_DATE = #{lDate}


                 and L_RULE_NO in ${lRuleNo}


                and L_DAILY_INSTRUCTION_NO in

				(

				select L_DAILY_INSTRUCTION_NO from T_COMP_CHECKINSSTOCK where C_BUSIN_CLASS = #{bussType}

				)


                and C_VOILATE_TYPE  =  #{cVoilateType}

	select 

  from T_COMP_RTCHECKRES a 
  WHERE a.L_SERIAL_NO = #{lSerialNo} and a.L_DATE = #{lDate}
